"use client";

import React, { useState, useEffect } from "react";
import type { CSSProperties, ReactNode } from "react";
import { cn } from "@/lib/utils";

interface MenuOption {
  key: string;
  value: string;
}

interface STopMenuProps {
  style?: CSSProperties;
  className?: string;
  leftCorner?: ReactNode;
  logo?: ReactNode;
  search?: ReactNode;
  menuOptions?: MenuOption[];
  operations?: ReactNode[];
  avatar?: ReactNode;
  content?: ReactNode;
  showLeftMenu?: boolean;
  onLeftCornerClick?: (visible: boolean) => void;
}

interface SSubTopMenuProps {
  logo?: ReactNode;
  menuOptions?: MenuOption[];
  operations?: ReactNode[] | ReactNode;
  style?: CSSProperties;
}

function HamburgerIcon() {
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
      <path d="M3 5h14M3 10h14M3 15h14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
    </svg>
  );
}

function SearchIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
      <circle cx="7" cy="7" r="4.5" stroke="currentColor" strokeWidth="1.5" />
      <path d="M10.5 10.5L14 14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
    </svg>
  );
}

const STopMenu: React.FC<STopMenuProps> = (props) => {
  const {
    style,
    className,
    leftCorner,
    logo,
    search,
    menuOptions = [],
    operations = [],
    avatar,
    content,
    showLeftMenu,
    onLeftCornerClick,
  } = props;

  const [menuVisible, setMenuVisible] = useState(!showLeftMenu);
  const [selectedKey, setSelectedKey] = useState<string>(menuOptions[0]?.key ?? "");

  useEffect(() => {
    if (showLeftMenu !== undefined) setMenuVisible(!showLeftMenu);
  }, [showLeftMenu]);

  const handleToggle = () => {
    const next = !menuVisible;
    setMenuVisible(next);
    onLeftCornerClick?.(next);
  };

  return (
    <div
      className={cn(className)}
      style={{
        display: "flex",
        alignItems: "center",
        height: 56,
        backgroundColor: "var(--color-bg-1, #fff)",
        borderBottom: "1px solid var(--color-border-2, #e5e6eb)",
        padding: "0 16px",
        gap: 16,
        ...style,
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 12, flexShrink: 0 }}>
        {leftCorner ?? (
          <div
            onClick={handleToggle}
            style={{
              cursor: "pointer",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              width: 32,
              height: 32,
              borderRadius: "var(--border-radius-small, 4px)",
              color: "var(--color-text-2, #4e5969)",
            }}
          >
            <HamburgerIcon />
          </div>
        )}
        {logo ?? (
          <div
            style={{
              width: 32,
              height: 32,
              borderRadius: "var(--border-radius-small, 4px)",
              backgroundColor: "var(--color-fill-3, #c9cdd4)",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 12,
              color: "#fff",
              fontWeight: 600,
            }}
          >
            L
          </div>
        )}
      </div>

      <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", minWidth: 0 }}>
        {content}
      </div>

      <div style={{ display: "flex", alignItems: "center", gap: 16, flexShrink: 0 }}>
        {search ?? (
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 6,
              padding: "0 10px",
              height: 32,
              borderRadius: "var(--border-radius-small, 4px)",
              border: "1px solid var(--color-border-3)",
              backgroundColor: "transparent",
              color: "var(--color-text-3, #86909c)",
              fontSize: 14,
            }}
          >
            <SearchIcon />
            <input
              type="text"
              placeholder="请输入关键词进行搜索"
              style={{
                border: "none",
                outline: "none",
                background: "transparent",
                color: "var(--color-text-1, #1d2129)",
                fontSize: 14,
                width: 160,
              }}
            />
          </div>
        )}

        {menuOptions.length > 0 && (
          <div style={{ display: "flex", alignItems: "center", gap: 4, height: 56 }}>
            {menuOptions.map((opt) => {
              const isActive = opt.key === selectedKey;
              return (
                <div
                  key={opt.key}
                  onClick={() => setSelectedKey(opt.key)}
                  style={{
                    position: "relative",
                    padding: "0 12px",
                    height: 56,
                    display: "flex",
                    alignItems: "center",
                    cursor: "pointer",
                    fontSize: 14,
                    color: isActive ? "rgb(var(--primary-6, 22 93 255))" : "var(--color-text-2, #4e5969)",
                    fontWeight: isActive ? 500 : 400,
                    transition: "color 0.2s",
                  }}
                >
                  {opt.value}
                  {isActive && (
                    <div
                      style={{
                        position: "absolute",
                        bottom: 0,
                        left: 12,
                        right: 12,
                        height: 2,
                        backgroundColor: "rgb(var(--primary-6, 22 93 255))",
                        borderRadius: 1,
                      }}
                    />
                  )}
                </div>
              );
            })}
          </div>
        )}

        {operations.length > 0 && (
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            {operations.map((op, idx) => (
              <div key={idx}>{op}</div>
            ))}
          </div>
        )}

        {avatar ?? (
          <div
            style={{
              width: 32,
              height: 32,
              borderRadius: "50%",
              backgroundColor: "#aaa",
              flexShrink: 0,
            }}
          />
        )}
      </div>
    </div>
  );
};

export const SSubTopMenu: React.FC<SSubTopMenuProps> = (props) => {
  const { logo, menuOptions = [], operations, style } = props;
  const [selectedKey, setSelectedKey] = useState<string>(menuOptions[0]?.key ?? "");

  const opArray = Array.isArray(operations) ? operations : operations ? [operations] : [];

  return (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        height: 48,
        backgroundColor: "var(--color-bg-1, #fff)",
        borderBottom: "1px solid var(--color-border-2, #e5e6eb)",
        padding: "0 16px",
        gap: 16,
        ...style,
      }}
    >
      <div style={{ display: "flex", alignItems: "center", gap: 12, flexShrink: 0 }}>
        {logo}
      </div>

      {menuOptions.length > 0 && (
        <div style={{ display: "flex", alignItems: "center", gap: 4, height: 48, flex: 1 }}>
          {menuOptions.map((opt) => {
            const isActive = opt.key === selectedKey;
            return (
              <div
                key={opt.key}
                onClick={() => setSelectedKey(opt.key)}
                style={{
                  position: "relative",
                  padding: "0 12px",
                  height: 48,
                  display: "flex",
                  alignItems: "center",
                  cursor: "pointer",
                  fontSize: 14,
                  color: isActive ? "rgb(var(--primary-6, 22 93 255))" : "var(--color-text-2, #4e5969)",
                  fontWeight: isActive ? 500 : 400,
                  transition: "color 0.2s",
                }}
              >
                {opt.value}
                {isActive && (
                  <div
                    style={{
                      position: "absolute",
                      bottom: 0,
                      left: 12,
                      right: 12,
                      height: 2,
                      backgroundColor: "rgb(var(--primary-6, 22 93 255))",
                      borderRadius: 1,
                    }}
                  />
                )}
              </div>
            );
          })}
        </div>
      )}

      {opArray.length > 0 && (
        <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
          {opArray.map((op, idx) => (
            <div key={idx}>{op}</div>
          ))}
        </div>
      )}
    </div>
  );
};

export type { MenuOption, STopMenuProps, SSubTopMenuProps };
export default STopMenu;
